payload.text:
Replace current Manifest.json with

{
  "name": "KA V2",
  "short_name": "KA V2",
  "description": "StreakWise Analytics is a comprehensive productivity app that helps students study sessions with a Pomodoro timer, monitor progress with analytics, and stay motivated with achievements and goals.",
  "start_url": "/index.html",
  "display": "standalone",
  "background_color": "#fbfbfb",
  "theme_color": "#ffffff",
  "icons": [
    {
      "src": "icons/192x192/icon-192x192.png",
      "sizes": "192x192",
      "type": "image/png"
    },
    {
      "src": "icons/512x512/icon-512x512.png",
      "sizes": "512x512",
      "type": "image/png"
    }
  ]
}


And service-worker.js with
const CACHE_NAME = 'pwa-test-cache-v1';
const urlsToCache = [
  '/',
  '/index.html',
  '/manifest.json',
  '/icons/icon-192x192.png',
  '/icons/icon-512x512.png'
];

self.addEventListener('install', event => {
  event.waitUntil(
    caches.open(CACHE_NAME)
      .then(cache => cache.addAll(urlsToCache))
  );
});

self.addEventListener('fetch', event => {
  event.respondWith(
    caches.match(event.request)
      .then(response => response || fetch(event.request))
  );
});

